import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import { ResultsProvider } from './context/ResultsContext';
import ProtectedRoute from './components/ProtectedRoute';
import DashboardLayout from './components/DashboardLayout';
import './styles/global.css';

// Pages
import Landing from './pages/Landing';
import { Login, Register } from './pages/Auth';
import Dashboard from './pages/Dashboard';
import AptitudeRound from './pages/AptitudeRound';
import TechnicalRound from './pages/TechnicalRound';
import { BehavioralRound, ResultPage, Analytics, Leaderboard, Profile } from './pages/OtherPages';

// ─── Layout Wrapper for dashboard pages ──────────────────────
function WithLayout({ children }) {
  return <DashboardLayout>{children}</DashboardLayout>;
}

// ─── Protected + Layout wrapper ───────────────────────────────
function ProtectedWithLayout({ children }) {
  return (
    <ProtectedRoute>
      <WithLayout>{children}</WithLayout>
    </ProtectedRoute>
  );
}

// ─── Protected WITHOUT layout (full-screen round pages) ───────
function ProtectedNoLayout({ children }) {
  return <ProtectedRoute>{children}</ProtectedRoute>;
}

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <ResultsProvider>
          <Routes>
            {/* ── Public ── */}
            <Route path="/" element={<Landing />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />

            {/* ── Dashboard (with sidebar) ── */}
            <Route path="/dashboard" element={<ProtectedWithLayout><Dashboard /></ProtectedWithLayout>} />
            <Route path="/analytics"  element={<ProtectedWithLayout><Analytics /></ProtectedWithLayout>} />
            <Route path="/leaderboard"element={<ProtectedWithLayout><Leaderboard /></ProtectedWithLayout>} />
            <Route path="/profile"    element={<ProtectedWithLayout><Profile /></ProtectedWithLayout>} />

            {/* ── Round Result pages (with sidebar) ── */}
            <Route path="/aptitude/result"  element={<ProtectedWithLayout><ResultPage type="aptitude" /></ProtectedWithLayout>} />
            <Route path="/technical/result" element={<ProtectedWithLayout><ResultPage type="technical" /></ProtectedWithLayout>} />
            <Route path="/behavioral/result"element={<ProtectedWithLayout><ResultPage type="behavioral" /></ProtectedWithLayout>} />

            {/* ── Round pages (full-screen, no sidebar) ── */}
            <Route path="/aptitude"  element={<ProtectedNoLayout><AptitudeRound /></ProtectedNoLayout>} />
            <Route path="/technical" element={<ProtectedNoLayout><TechnicalRound /></ProtectedNoLayout>} />
            <Route path="/behavioral"element={<ProtectedNoLayout><BehavioralRound /></ProtectedNoLayout>} />

            {/* ── Catch all ── */}
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </ResultsProvider>
      </AuthProvider>
    </BrowserRouter>
  );
}
